  1	import * as React from 'react';
  2	import { Tag, DeleteObjectsCommandOutput } from '@aws-sdk/client-s3';
  3	import { S3Context } from '@odf/core/components/s3-browser/s3-context';
  4	import {
  5	  OBJECT_CACHE_KEY_SUFFIX,
  6	  OBJECT_TAGGING_CACHE_KEY_SUFFIX,
  7	  PREFIX,
  8	} from '@odf/core/constants';
  9	import { ObjectCrFormat } from '@odf/core/types';
 10	import {
 11	  replacePathFromName,
 12	  getObjectVersionId,
 13	  convertObjectDataToCrFormat,
 14	  sortByLastModified,
 15	} from '@odf/core/utils';
 16	import {
 17	  DASH,
 18	  DrawerHead,
 19	  getName,
 20	  LoadingBox,
 21	  useCustomTranslation,
 22	} from '@odf/shared';
 23	import { PaginatedListPage } from '@odf/shared/list-page';
 24	import { S3Commands } from '@odf/shared/s3';
 25	import { CopyToClipboard } from '@odf/shared/utils/copy-to-clipboard';
 26	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 27	import { TFunction } from 'react-i18next';
 28	import { useParams, useSearchParams } from 'react-router-dom-v5-compat';
 29	import useSWR from 'swr';
 30	import {
 31	  Alert,
 32	  AlertVariant,
 33	  Drawer,
 34	  DrawerActions,
 35	  DrawerCloseButton,
 36	  DrawerContent,
 37	  DrawerContentBody,
 38	  DrawerPanelBody,
 39	  DrawerPanelContent,
 40	  Dropdown,
 41	  DropdownItem,
 42	  DropdownList,
 43	  Grid,
 44	  GridItem,
 45	  Label,
 46	  LabelGroup,
 47	  Level,
 48	  LevelItem,
 49	  MenuToggle,
 50	  Title,
 51	  Tab,
 52	  Tabs,
 53	  TabTitleText,
 54	  PaginationVariant,
 55	  TextContent,
 56	  Text,
 57	  TextVariants,
 58	} from '@patternfly/react-core';
 59	import { TagIcon } from '@patternfly/react-icons';
 60	import { IAction, TableVariant } from '@patternfly/react-table';
 61	import { ObjectsDeleteResponse } from '../../../modals/s3-browser/delete-objects/DeleteObjectsModal';
 62	import { ExtraProps, DeletionAlerts } from '../objects-list/ObjectsList';
 63	import { getHeaderColumns, ObjectVersionsTableRow } from './table-components';
 64	import './object-details-sidebar.scss';
 65	
 66	type ObjectDetailsSidebarContentProps = {
 67	  closeSidebar: () => void;
 68	  object: ObjectCrFormat;
 69	  objectActions: React.MutableRefObject<IAction[]>;
 70	  extraProps?: ExtraProps;
 71	  showVersioning: boolean;
 72	};
 73	
 74	type ObjectOverviewProps = {
 75	  object: ObjectCrFormat;
 76	  showVersioning?: boolean;
 77	  s3Client: S3Commands;
 78	  bucketName: string;
 79	  objShortenedName?: string;
 80	};
 81	
 82	type ObjectVersionsProps = {
 83	  object: ObjectCrFormat;
 84	  s3Client: S3Commands;
 85	  bucketName: string;
 86	  extraProps: ExtraProps;
 87	  foldersPath: string;
 88	};
 89	
 90	const ItemHeading: React.FC<{ text: string }> = ({ text }) => (
 91	  <TextContent>
 92	    <Text component={TextVariants.h5}>{text}</Text>
 93	  </TextContent>
 94	);
 95	
 96	const fetchVersions = async ({
 97	  setInProgress,
 98	  setObjectVersions,
 99	  setError,
100	  s3Client,
101	  bucketName,
102	  objectKey,
103	  t,
104	}: {
105	  setInProgress: React.Dispatch<React.SetStateAction<boolean>>;
106	  setObjectVersions: React.Dispatch<React.SetStateAction<ObjectCrFormat[]>>;
107	  setError: React.Dispatch<any>;
108	  s3Client: S3Commands;
109	  bucketName: string;
110	  objectKey: string;
111	  t: TFunction;
112	}) => {
113	  try {
114	    setInProgress(true);
115	
116	    let allObjects: ObjectCrFormat[] = [];
117	    let isTruncated = true;
118	    let stopFetchEarly = false;
119	    let keyMarker: string;
120	    let versionIdMarker: string;
121	
122	    while (isTruncated && !stopFetchEarly) {
123	      // eslint-disable-next-line no-await-in-loop
124	      const objects = await s3Client.listObjectVersions({
125	        Bucket: bucketName,
126	        Prefix: objectKey,
127	        KeyMarker: keyMarker,
128	        VersionIdMarker: versionIdMarker,
129	      });
130	
131	      const objectVersions: ObjectCrFormat[] = [];
132	      for (const v of objects?.Versions || []) {
133	        if (v.Key === objectKey)
134	          objectVersions.push(convertObjectDataToCrFormat(v, t, false, false));
135	        else stopFetchEarly = true;
136	      }
137	
138	      const objectDeleteMarkers: ObjectCrFormat[] = [];
139	      for (const d of objects?.DeleteMarkers || []) {
140	        if (d.Key === objectKey)
141	          objectDeleteMarkers.push(
142	            convertObjectDataToCrFormat(d, t, false, true)
143	          );
144	        else stopFetchEarly = true;
145	      }
146	
147	      allObjects = [...allObjects, ...objectVersions, ...objectDeleteMarkers];
148	
149	      isTruncated = objects.IsTruncated;
150	      keyMarker = objects.NextKeyMarker;
151	      versionIdMarker = objects.NextVersionIdMarker;
152	    }
153	
154	    allObjects.sort(sortByLastModified);
155	    setObjectVersions(allObjects);
156	  } catch (error) {
157	    setError(error);
158	  } finally {
159	    setInProgress(false);
160	  }
161	};
162	
163	const ObjectVersions: React.FC<ObjectVersionsProps> = ({
164	  object,
165	  s3Client,
166	  bucketName,
167	  foldersPath,
168	  extraProps,
169	}) => {
170	  const { t } = useCustomTranslation();
171	
172	  const {
173	    setDeleteResponse: setDeleteResponseListPage,
174	    refreshTokens,
175	    closeObjectSidebar,
176	  } = extraProps;
177	
178	  const launcher = useModal();
179	
180	  const [objectVersions, setObjectVersions] = React.useState<ObjectCrFormat[]>(
181	    []
182	  );
183	  const [inProgress, setInProgress] = React.useState(false);
184	  const [error, setError] = React.useState(null);
185	  // used for storing API's response on performing delete operation on object version
186	  const [deleteResponseSideBar, setDeleteResponseSideBar] =
187	    React.useState<ObjectsDeleteResponse>({
188	      selectedObjects: [] as ObjectCrFormat[],
189	      deleteResponse: {} as DeleteObjectsCommandOutput,
190	    });
191	
192	  const hasOnlySingleVersion = objectVersions.length === 1;
193	  const objectKey = getName(object);
194	
195	  // initial fetch on first mount or on object version deletion
196	  // or if sidebar re-renders with a different object
197	  React.useEffect(() => {
198	    fetchVersions({
199	      setInProgress,
200	      setObjectVersions,
201	      setError,
202	      s3Client,
203	      bucketName,
204	      objectKey,
205	      t,
206	    });
207	    // eslint-disable-next-line react-hooks/exhaustive-deps
208	  }, [deleteResponseSideBar, objectKey]);
209	
210	  return (
211	    <>
212	      <TextContent className="pf-v6-u-my-sm">
213	        <Text component={TextVariants.small}>
214	          {t(
215	            'Perform actions such as sharing, downloading, previewing, and deleting different versions of an object. For a comprehensive view of each version, enable "List all versions."'
216	          )}
217	        </Text>
218	      </TextContent>
219	      <DeletionAlerts
220	        deleteResponse={deleteResponseSideBar}
221	        foldersPath={foldersPath}
222	      />
223	      <PaginatedListPage
224	        filteredData={objectVersions}
225	        noData={hasOnlySingleVersion}
226	        hideFilter
227	        composableTableProps={{
228	          columns: getHeaderColumns(t),
229	          RowComponent: ObjectVersionsTableRow,
230	          extraProps: {
231	            launcher,
232	            bucketName,
233	            s3Client,
234	            foldersPath,
235	            // if object has only single version, display deletion status on the main list page instead of the sidebar
236	            // sidebar will close in this case as no objects/versions are left to display
237	            setDeleteResponse: hasOnlySingleVersion
238	              ? setDeleteResponseListPage
239	              : setDeleteResponseSideBar,
240	            ...(hasOnlySingleVersion && { refreshTokens }),
241	            ...(hasOnlySingleVersion && { closeObjectSidebar }),
242	          },
243	          unfilteredData: objectVersions as [],
244	          loaded: !inProgress,
245	          loadError: error,
246	          variant: TableVariant.compact,
247	        }}
248	        paginationProps={{
249	          variant: PaginationVariant.top,
250	          isCompact: true,
251	          dropDirection: 'down',
252	          perPageOptions: [{ title: '10', value: 10 }],
253	        }}
254	      />
255	    </>
256	  );
257	};
258	
259	const ObjectOverview: React.FC<ObjectOverviewProps> = ({
260	  object,
261	  showVersioning,
262	  s3Client,
263	  bucketName,
264	  objShortenedName,
265	}) => {
266	  const { t } = useCustomTranslation();
267	
268	  const objectKey = getName(object);
269	  const versionId = getObjectVersionId(object);
270	  const lastModified = object?.apiResponse?.lastModified;
271	  const isDeleteMarker = object?.isDeleteMarker;
272	
273	  const { data: objectData, isLoading: isObjectDataLoading } = useSWR(
274	    // don't fetch if object is a delete marker ("getObject" not supported)
275	    isDeleteMarker
276	      ? null
277	      : `${s3Client.providerType}-${objectKey}-${lastModified}-${OBJECT_CACHE_KEY_SUFFIX}`,
278	    () =>
279	      s3Client.getObject({
280	        Bucket: bucketName,
281	        Key: objectKey,
282	        ...(showVersioning && { VersionId: versionId }),
283	      })
284	  );
285	  const { data: tagData, isLoading: isTagDataLoading } = useSWR(
286	    // don't fetch if object is a delete marker ("getObjectTagging" not supported)
287	    isDeleteMarker
288	      ? null
289	      : `${s3Client.providerType}-${objectKey}-${lastModified}-${OBJECT_TAGGING_CACHE_KEY_SUFFIX}}`,
290	    () =>
291	      s3Client.getObjectTagging({
292	        Bucket: bucketName,
293	        Key: objectKey,
294	        ...(showVersioning && { VersionId: versionId }),
295	      })
296	  );
297	
298	  const tags = tagData?.TagSet?.map((tag: Tag) => (
299	    <Label className="pf-v6-u-mr-xs" color="grey" icon={<TagIcon />}>
300	      {tag.Key}
301	      {tag.Value && `=${tag.Value}`}
302	    </Label>
303	  ));
304	
305	  const metadata = [];
306	  // @TODO: investigate why the Metadata is not returned (unlike in the CLI response).
307	  if (objectData?.Metadata) {
308	    for (const [key, value] of Object.entries(objectData?.Metadata)) {
309	      metadata.push(
310	        <div>
311	          {key}
312	          {value && `=${value}`}
313	        </div>
314	      );
315	    }
316	  }
317	
318	  const isLoading = isObjectDataLoading || isTagDataLoading;
319	
320	  return isLoading ? (
321	    <LoadingBox />
322	  ) : (
323	    <Grid className="odf-object-sidebar__data-grid pf-v6-u-mt-sm" hasGutter>
324	      <GridItem span={6}>
325	        <ItemHeading text={t('Name')} />
326	        {objShortenedName}
327	      </GridItem>
328	      <GridItem span={6}>
329	        <ItemHeading text={t('Key')} />
330	        <Level>
331	          <LevelItem className="odf-object-sidebar__key">{objectKey}</LevelItem>
332	          <LevelItem>
333	            <CopyToClipboard value={objectKey} iconOnly={true} />
334	          </LevelItem>
335	        </Level>
336	      </GridItem>
337	      {showVersioning && (
338	        <GridItem span={6}>
339	          <ItemHeading text={t('Version')} />
340	          {objectData?.VersionId || versionId || DASH}
341	        </GridItem>
342	      )}
343	      <GridItem span={6}>
344	        <ItemHeading text={t('Owner')} />
345	        {object.apiResponse?.ownerName}
346	      </GridItem>
347	      <GridItem span={6}>
348	        <ItemHeading text={t('Type')} />
349	        {isDeleteMarker ? t('Delete marker') : objectData?.ContentType}
350	      </GridItem>
351	      <GridItem span={6}>
352	        <ItemHeading text={t('Last modified')} />
353	        {lastModified}
354	      </GridItem>
355	      <GridItem span={6}>
356	        <ItemHeading text={t('Size')} />
357	        {object.apiResponse.size}
358	      </GridItem>
359	      <GridItem span={6}>
360	        <ItemHeading text={t('Entity tag (ETag)')} />
361	        {objectData?.ETag || DASH}
362	      </GridItem>
363	      <GridItem span={12}>
364	        <ItemHeading text={t('Tags')} />
365	        {tags?.length > 0 ? <LabelGroup>{tags}</LabelGroup> : DASH}
366	      </GridItem>
367	      <GridItem span={12}>
368	        <ItemHeading text={t('Metadata')} />
369	        {metadata.length > 0 ? metadata : DASH}
370	      </GridItem>
371	    </Grid>
372	  );
373	};
374	
375	const ObjectDetailsSidebarContent: React.FC<
376	  ObjectDetailsSidebarContentProps
377	> = ({ closeSidebar, object, objectActions, extraProps, showVersioning }) => {
378	  const { t } = useCustomTranslation();
379	
380	  const [isOpen, setIsOpen] = React.useState(false);
381	  const [activeTab, setActiveTab] = React.useState(0);
382	  const dropdownToggleRef = React.useRef();
383	
384	  const onDropdownToggleClick = () => {
385	    setIsOpen(!isOpen);
386	  };
387	  const onDropdownSelect = () => {
388	    setIsOpen(false);
389	  };
390	
391	  const actionItems: IAction[] = objectActions.current;
392	
393	  const { s3Client } = React.useContext(S3Context);
394	  const [searchParams] = useSearchParams();
395	  const { bucketName } = useParams();
396	
397	  const foldersPath = searchParams.get(PREFIX);
398	  const objName = object ? replacePathFromName(object, foldersPath) : '';
399	  const isDeleteMarker = object?.isDeleteMarker;
400	
401	  const dropdownItems = [];
402	  if (Array.isArray(actionItems)) {
403	    actionItems.forEach((action: IAction) =>
404	      dropdownItems.push(
405	        <DropdownItem onClick={action.onClick} isDisabled={action?.isDisabled}>
406	          {action.title}
407	        </DropdownItem>
408	      )
409	    );
410	  }
411	
412	  return (
413	    <>
414	      <DrawerHead>
415	        <Title headingLevel="h3">{objName}</Title>
416	        <DrawerActions>
417	          <DrawerCloseButton onClick={closeSidebar} />
418	        </DrawerActions>
419	        <Dropdown
420	          isOpen={isOpen}
421	          onSelect={onDropdownSelect}
422	          toggle={{
423	            toggleNode: (
424	              <MenuToggle
425	                className="odf-object-sidebar__dropdown"
426	                ref={dropdownToggleRef}
427	                onClick={onDropdownToggleClick}
428	              >
429	                {t('Actions')}
430	              </MenuToggle>
431	            ),
432	            toggleRef: dropdownToggleRef,
433	          }}
434	        >
435	          <DropdownList>{dropdownItems}</DropdownList>
436	        </Dropdown>
437	      </DrawerHead>
438	      {isDeleteMarker && (
439	        <Alert
440	          isInline
441	          variant={AlertVariant.info}
442	          title={t('Why this object has a delete marker?')}
443	          className="pf-v6-u-m-sm"
444	        >
445	          <p>
446	            {t(
447	              "When an object is deleted, a delete marker is created as the current version of that object. A delete marker prevents the object from being visible when listing the objects in a bucket but does not delete the object's data. If you permanently delete the delete marker, the object can be fully restored."
448	            )}
449	          </p>
450	        </Alert>
451	      )}
452	      <DrawerPanelBody>
453	        {showVersioning && (
454	          <ObjectOverview
455	            object={object}
456	            showVersioning={true}
457	            s3Client={s3Client}
458	            bucketName={bucketName}
459	            objShortenedName={objName}
460	          />
461	        )}
462	        {!showVersioning && (
463	          <Tabs
464	            activeKey={activeTab}
465	            onSelect={(_event, tabIndex) => setActiveTab(tabIndex as number)}
466	            unmountOnExit
467	          >
468	            <Tab
469	              eventKey={0}
470	              title={<TabTitleText>{t('Overview')}</TabTitleText>}
471	            >
472	              <ObjectOverview
473	                object={object}
474	                showVersioning={false}
475	                s3Client={s3Client}
476	                bucketName={bucketName}
477	                objShortenedName={objName}
478	              />
479	            </Tab>
480	            <Tab
481	              eventKey={1}
482	              title={<TabTitleText>{t('Versions')}</TabTitleText>}
483	            >
484	              <ObjectVersions
485	                object={object}
486	                s3Client={s3Client}
487	                bucketName={bucketName}
488	                foldersPath={foldersPath}
489	                extraProps={extraProps}
490	              />
491	            </Tab>
492	          </Tabs>
493	        )}
494	      </DrawerPanelBody>
495	    </>
496	  );
497	};
498	
499	type ObjectDetailsSidebarProps = {
500	  closeSidebar?: () => void;
501	  isExpanded: boolean;
502	  object?: ObjectCrFormat;
503	  objectActions?: React.MutableRefObject<IAction[]>;
504	  extraProps?: ExtraProps;
505	  wrappedContent: React.ReactNode;
506	  showVersioning: boolean;
507	};
508	
509	export const ObjectDetailsSidebar: React.FC<ObjectDetailsSidebarProps> = ({
510	  closeSidebar,
511	  isExpanded,
512	  object,
513	  objectActions,
514	  extraProps,
515	  wrappedContent,
516	  showVersioning,
517	}) => {
518	  return (
519	    <Drawer isExpanded={isExpanded} position="right">
520	      <DrawerContent
521	        panelContent={
522	          <DrawerPanelContent defaultSize="700px" isResizable>
523	            {object && (
524	              <ObjectDetailsSidebarContent
525	                closeSidebar={closeSidebar}
526	                object={object}
527	                objectActions={objectActions}
528	                extraProps={extraProps}
529	                showVersioning={showVersioning}
530	              />
531	            )}
532	          </DrawerPanelContent>
533	        }
534	      >
535	        <DrawerContentBody>{wrappedContent}</DrawerContentBody>
536	      </DrawerContent>
537	    </Drawer>
538	  );
539	};

