 25	import { CopyToClipboard } from '@odf/shared/utils/copy-to-clipboard';
 26	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 27	import { TFunction } from 'react-i18next';
 28	import { useParams, useSearchParams } from 'react-router-dom-v5-compat';
 29	import useSWR from 'swr';
 30	import {
 31	  Alert,
 32	  AlertVariant,
 33	  Drawer,
 34	  DrawerActions,
 35	  DrawerCloseButton,
 36	  DrawerContent,
 37	  DrawerContentBody,
