 57	} from '@patternfly/react-core';
 58	import { TagIcon } from '@patternfly/react-icons';
 59	import { IAction, TableVariant } from '@patternfly/react-table';
 60	import { ObjectsDeleteResponse } from '../../../modals/s3-browser/delete-objects/DeleteObjectsModal';
 61	import { ExtraProps, DeletionAlerts } from '../objects-list/ObjectsList';
 62	import { getHeaderColumns, ObjectVersionsTableRow } from './table-components';
 63	import './object-details-sidebar.scss';
 64	
 65	type ObjectDetailsSidebarContentProps = {
 66	  closeSidebar: () => void;
 67	  object: ObjectCrFormat;
 68	  objectActions: React.MutableRefObject<IAction[]>;
 69	  extraProps?: ExtraProps;
 70	  showVersioning: boolean;
 71	};
 72	
 73	type ObjectOverviewProps = {
 74	  object: ObjectCrFormat;
 75	  showVersioning?: boolean;
 76	  s3Client: S3Commands;
 77	  bucketName: string;
 78	  objShortenedName?: string;
 79	};
 80	
 81	type ObjectVersionsProps = {
 82	  object: ObjectCrFormat;
 83	  s3Client: S3Commands;
 84	  bucketName: string;
 85	  extraProps: ExtraProps;
 86	  foldersPath: string;
 87	};
 88	
 89	const ItemHeading: React.FC<{ text: string }> = ({ text }) => (
 90	  <Content component={ContentVariants.h5}>{text}</Content>
 91	);
 92	
 93	const fetchVersions = async ({
 94	  setInProgress,
 95	  setObjectVersions,
 96	  setError,
 97	  s3Client,
 98	  bucketName,
 99	  objectKey,
100	  t,
101	}: {
102	  setInProgress: React.Dispatch<React.SetStateAction<boolean>>;
103	  setObjectVersions: React.Dispatch<React.SetStateAction<ObjectCrFormat[]>>;
104	  setError: React.Dispatch<any>;
105	  s3Client: S3Commands;
106	  bucketName: string;
107	  objectKey: string;
108	  t: TFunction;
109	}) => {
110	  try {
111	    setInProgress(true);
112	
113	    let allObjects: ObjectCrFormat[] = [];
114	    let isTruncated = true;
115	    let stopFetchEarly = false;
116	    let keyMarker: string;
117	    let versionIdMarker: string;
118	
119	    while (isTruncated && !stopFetchEarly) {
120	      // eslint-disable-next-line no-await-in-loop
121	      const objects = await s3Client.listObjectVersions({
122	        Bucket: bucketName,
123	        Prefix: objectKey,
124	        KeyMarker: keyMarker,
125	        VersionIdMarker: versionIdMarker,
126	      });
127	
128	      const objectVersions: ObjectCrFormat[] = [];
129	      for (const v of objects?.Versions || []) {
130	        if (v.Key === objectKey)
131	          objectVersions.push(convertObjectDataToCrFormat(v, t, false, false));
132	        else stopFetchEarly = true;
133	      }
134	
135	      const objectDeleteMarkers: ObjectCrFormat[] = [];
136	      for (const d of objects?.DeleteMarkers || []) {
137	        if (d.Key === objectKey)
138	          objectDeleteMarkers.push(
139	            convertObjectDataToCrFormat(d, t, false, true)
140	          );
141	        else stopFetchEarly = true;
142	      }
143	
144	      allObjects = [...allObjects, ...objectVersions, ...objectDeleteMarkers];
145	
146	      isTruncated = objects.IsTruncated;
147	      keyMarker = objects.NextKeyMarker;
148	      versionIdMarker = objects.NextVersionIdMarker;
149	    }
150	
151	    allObjects.sort(sortByLastModified);
152	    setObjectVersions(allObjects);
153	  } catch (error) {
154	    setError(error);
155	  } finally {
156	    setInProgress(false);
157	  }
158	};
159	
160	const ObjectVersions: React.FC<ObjectVersionsProps> = ({
161	  object,
162	  s3Client,
163	  bucketName,
164	  foldersPath,
165	  extraProps,
166	}) => {
167	  const { t } = useCustomTranslation();
168	
169	  const {
170	    setDeleteResponse: setDeleteResponseListPage,
171	    refreshTokens,
172	    closeObjectSidebar,
173	  } = extraProps;
174	
175	  const launcher = useModal();
176	
177	  const [objectVersions, setObjectVersions] = React.useState<ObjectCrFormat[]>(
178	    []
179	  );
180	  const [inProgress, setInProgress] = React.useState(false);
181	  const [error, setError] = React.useState(null);
182	  // used for storing API's response on performing delete operation on object version
183	  const [deleteResponseSideBar, setDeleteResponseSideBar] =
184	    React.useState<ObjectsDeleteResponse>({
185	      selectedObjects: [] as ObjectCrFormat[],
186	      deleteResponse: {} as DeleteObjectsCommandOutput,
187	    });
188	
189	  const hasOnlySingleVersion = objectVersions.length === 1;
190	  const objectKey = getName(object);
191	
192	  // initial fetch on first mount or on object version deletion
193	  // or if sidebar re-renders with a different object
194	  React.useEffect(() => {
195	    fetchVersions({
196	      setInProgress,
197	      setObjectVersions,
198	      setError,
199	      s3Client,
200	      bucketName,
201	      objectKey,
202	      t,
203	    });
204	    // eslint-disable-next-line react-hooks/exhaustive-deps
205	  }, [deleteResponseSideBar, objectKey]);
206	
207	  return (
208	    <>
209	      <Content component={ContentVariants.small} className="pf-v6-u-my-sm">
210	        {t(
211	          'Perform actions such as sharing, downloading, previewing, and deleting different versions of an object. For a comprehensive view of each version, enable "List all versions."'
212	        )}
213	      </Content>
214	      <DeletionAlerts
215	        deleteResponse={deleteResponseSideBar}
216	        foldersPath={foldersPath}
217	      />
218	      <PaginatedListPage
219	        filteredData={objectVersions}
220	        noData={hasOnlySingleVersion}
221	        hideFilter
222	        composableTableProps={{
223	          columns: getHeaderColumns(t),
224	          RowComponent: ObjectVersionsTableRow,
225	          extraProps: {
226	            launcher,
227	            bucketName,
228	            s3Client,
229	            foldersPath,
230	            // if object has only single version, display deletion status on the main list page instead of the sidebar
231	            // sidebar will close in this case as no objects/versions are left to display
232	            setDeleteResponse: hasOnlySingleVersion
233	              ? setDeleteResponseListPage
234	              : setDeleteResponseSideBar,
235	            ...(hasOnlySingleVersion && { refreshTokens }),
236	            ...(hasOnlySingleVersion && { closeObjectSidebar }),
237	          },
238	          unfilteredData: objectVersions as [],
239	          loaded: !inProgress,
240	          loadError: error,
241	          variant: TableVariant.compact,
242	        }}
243	        paginationProps={{
244	          variant: PaginationVariant.top,
245	          isCompact: true,
246	          dropDirection: 'down',
247	          perPageOptions: [{ title: '10', value: 10 }],
248	        }}
249	      />
250	    </>
251	  );
252	};
253	
254	const ObjectOverview: React.FC<ObjectOverviewProps> = ({
255	  object,
256	  showVersioning,
257	  s3Client,
258	  bucketName,
259	  objShortenedName,
260	}) => {
261	  const { t } = useCustomTranslation();
262	
263	  const objectKey = getName(object);
264	  const versionId = getObjectVersionId(object);
265	  const lastModified = object?.apiResponse?.lastModified;
266	  const isDeleteMarker = object?.isDeleteMarker;
267	
268	  const { data: objectData, isLoading: isObjectDataLoading } = useSWR(
269	    // don't fetch if object is a delete marker ("getObject" not supported)
270	    isDeleteMarker
271	      ? null
272	      : `${s3Client.providerType}-${objectKey}-${lastModified}-${OBJECT_CACHE_KEY_SUFFIX}`,
273	    () =>
274	      s3Client.getObject({
275	        Bucket: bucketName,
276	        Key: objectKey,
277	        ...(showVersioning && { VersionId: versionId }),
278	      })
279	  );
280	  const { data: tagData, isLoading: isTagDataLoading } = useSWR(
281	    // don't fetch if object is a delete marker ("getObjectTagging" not supported)
282	    isDeleteMarker
283	      ? null
284	      : `${s3Client.providerType}-${objectKey}-${lastModified}-${OBJECT_TAGGING_CACHE_KEY_SUFFIX}}`,
285	    () =>
286	      s3Client.getObjectTagging({
