322	      </GridItem>
323	      <GridItem span={6}>
324	        <ItemHeading text={t('Key')} />
325	        <Level>
326	          <LevelItem className="odf-object-sidebar__key">{objectKey}</LevelItem>
327	          <LevelItem>
328	            <CopyToClipboard value={objectKey} iconOnly={true} />
329	          </LevelItem>
330	        </Level>
331	      </GridItem>
332	      {showVersioning && (
333	        <GridItem span={6}>
334	          <ItemHeading text={t('Version')} />
335	          {objectData?.VersionId || versionId || DASH}
336	        </GridItem>
337	      )}
338	      <GridItem span={6}>
339	        <ItemHeading text={t('Owner')} />
340	        {object.apiResponse?.ownerName}
341	      </GridItem>
342	      <GridItem span={6}>
343	        <ItemHeading text={t('Type')} />
344	        {isDeleteMarker ? t('Delete marker') : objectData?.ContentType}
345	      </GridItem>
346	      <GridItem span={6}>
347	        <ItemHeading text={t('Last modified')} />
348	        {lastModified}
349	      </GridItem>
350	      <GridItem span={6}>
351	        <ItemHeading text={t('Size')} />
352	        {object.apiResponse.size}
353	      </GridItem>
354	      <GridItem span={6}>
355	        <ItemHeading text={t('Entity tag (ETag)')} />
356	        {objectData?.ETag || DASH}
357	      </GridItem>
358	      <GridItem span={12}>
359	        <ItemHeading text={t('Tags')} />
360	        {tags?.length > 0 ? <LabelGroup>{tags}</LabelGroup> : DASH}
361	      </GridItem>
362	      <GridItem span={12}>
363	        <ItemHeading text={t('Metadata')} />
364	        {metadata.length > 0 ? metadata : DASH}
365	      </GridItem>
366	    </Grid>
367	  );
368	};
