254	const ObjectOverview: React.FC<ObjectOverviewProps> = ({
255	  object,
256	  showVersioning,
257	  s3Client,
258	  bucketName,
259	  objShortenedName,
260	}) => {
261	  const { t } = useCustomTranslation();
262	
263	  const objectKey = getName(object);
264	  const versionId = getObjectVersionId(object);
265	  const lastModified = object?.apiResponse?.lastModified;
266	  const isDeleteMarker = object?.isDeleteMarker;
267	
268	  const { data: objectData, isLoading: isObjectDataLoading } = useSWR(
269	    // don't fetch if object is a delete marker ("getObject" not supported)
270	    isDeleteMarker
271	      ? null
272	      : `${s3Client.providerType}-${objectKey}-${lastModified}-${OBJECT_CACHE_KEY_SUFFIX}`,
273	    () =>
274	      s3Client.getObject({
275	        Bucket: bucketName,
276	        Key: objectKey,
277	        ...(showVersioning && { VersionId: versionId }),
278	      })
279	  );
280	  const { data: tagData, isLoading: isTagDataLoading } = useSWR(
281	    // don't fetch if object is a delete marker ("getObjectTagging" not supported)
282	    isDeleteMarker
283	      ? null
284	      : `${s3Client.providerType}-${objectKey}-${lastModified}-${OBJECT_TAGGING_CACHE_KEY_SUFFIX}}`,
285	    () =>
286	      s3Client.getObjectTagging({
287	        Bucket: bucketName,
288	        Key: objectKey,
289	        ...(showVersioning && { VersionId: versionId }),
290	      })
291	  );
292	
293	  const tags = tagData?.TagSet?.map((tag: Tag) => (
294	    <Label className="pf-v6-u-mr-xs" color="grey" icon={<TagIcon />}>
295	      {tag.Key}
296	      {tag.Value && `=${tag.Value}`}
297	    </Label>
298	  ));
299	
300	  const metadata = [];
301	  // @TODO: investigate why the Metadata is not returned (unlike in the CLI response).
302	  if (objectData?.Metadata) {
303	    for (const [key, value] of Object.entries(objectData?.Metadata)) {
304	      metadata.push(
305	        <div>
306	          {key}
307	          {value && `=${value}`}
308	        </div>
309	      );
310	    }
311	  }
312	
313	  const isLoading = isObjectDataLoading || isTagDataLoading;
314	
315	  return isLoading ? (
316	    <LoadingBox />
317	  ) : (
318	    <Grid className="odf-object-sidebar__data-grid pf-v6-u-mt-sm" hasGutter>
319	      <GridItem span={6}>
